import { TinyColor } from '@ctrl/tinycolor';
import type { Color } from '../types';

// 暗色主题颜色映射关系表
const darkColorMap = [
  { index: 7, opacity: 0.15, level: 50 },
  { index: 6, opacity: 0.25, level: 100 },
  { index: 5, opacity: 0.3, level: 200 },
  { index: 5, opacity: 0.45, level: 300 },
  { index: 5, opacity: 0.65, level: 400 },
  { index: 5, opacity: 0.85, level: 500 },
  { index: 4, opacity: 0.9, level: 600 },
  { index: 3, opacity: 0.95, level: 700 },
  { index: 2, opacity: 0.97, level: 800 },
  { index: 1, opacity: 0.98, level: 900 },
];

export default (
  lightColors: Color[],
  props: {
    backgroundColor: string;
  },
): Color[] =>
  darkColorMap.map(({ index, opacity, level }) => {
    const { value } = lightColors[index];
    const darkColorString = new TinyColor(props.backgroundColor).mix(value, opacity * 100).toHexString();
    return {
      level,
      value: darkColorString,
    };
  });
